import{_ as p,c as t,b as l,a as s,d as a,e as o,r as c,o as i}from"./app-CvT2DUHU.js";const u={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function k(d,n){const e=c("ExternalLinkIcon");return i(),t("div",null,[n[2]||(n[2]=l(`<h1 id="第-20-章-im-渠道系统" tabindex="-1"><a class="header-anchor" href="#第-20-章-im-渠道系统"><span>第 20 章　IM 渠道系统</span></a></h1><p>DeerFlow 不仅是一个 Web 应用，还可以作为 IM 机器人嵌入到 Telegram、Slack 和飞书中。本章将深入分析 IM 渠道系统的架构设计，从抽象基类到消息总线，再到三个具体渠道的实现。</p><h2 id="_20-1-channel-抽象基类" tabindex="-1"><a class="header-anchor" href="#_20-1-channel-抽象基类"><span>20.1 Channel 抽象基类</span></a></h2><p>所有 IM 渠道实现都继承自 <code>channels/base.py</code> 中的 <code>Channel</code> 抽象基类：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">Channel</span><span class="token punctuation">(</span>ABC<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token triple-quoted-string string">&quot;&quot;&quot;Base class for all IM channel implementations.</span>
<span class="line"></span>
<span class="line">    Each channel connects to an external messaging platform and:</span>
<span class="line">    1. Receives messages, wraps them as InboundMessage, publishes to the bus.</span>
<span class="line">    2. Subscribes to outbound messages and sends replies back to the platform.</span>
<span class="line">    &quot;&quot;&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> bus<span class="token punctuation">:</span> MessageBus<span class="token punctuation">,</span> config<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name</span>
<span class="line">        self<span class="token punctuation">.</span>bus <span class="token operator">=</span> bus</span>
<span class="line">        self<span class="token punctuation">.</span>config <span class="token operator">=</span> config</span>
<span class="line">        self<span class="token punctuation">.</span>_running <span class="token operator">=</span> <span class="token boolean">False</span></span>
<span class="line"></span>
<span class="line">    <span class="token decorator annotation punctuation">@abstractmethod</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"></span>
<span class="line">    <span class="token decorator annotation punctuation">@abstractmethod</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">stop</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"></span>
<span class="line">    <span class="token decorator annotation punctuation">@abstractmethod</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">send</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">:</span> OutboundMessage<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">send_file</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">:</span> OutboundMessage<span class="token punctuation">,</span> attachment<span class="token punctuation">:</span> ResolvedAttachment<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">bool</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">False</span>  <span class="token comment"># 默认不支持文件上传</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>基类定义了三个核心抽象方法（<code>start</code>、<code>stop</code>、<code>send</code>）和一个可选的文件上传方法。同时提供了两个模板方法：</p><p><strong><code>_make_inbound</code></strong> — 创建入站消息的工厂方法：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">_make_inbound</span><span class="token punctuation">(</span></span>
<span class="line">    self<span class="token punctuation">,</span> chat_id<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> user_id<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> text<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> <span class="token operator">*</span><span class="token punctuation">,</span></span>
<span class="line">    msg_type<span class="token punctuation">:</span> InboundMessageType <span class="token operator">=</span> InboundMessageType<span class="token punctuation">.</span>CHAT<span class="token punctuation">,</span></span>
<span class="line">    thread_ts<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">,</span></span>
<span class="line">    files<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span><span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">,</span></span>
<span class="line">    metadata<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> InboundMessage<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">return</span> InboundMessage<span class="token punctuation">(</span></span>
<span class="line">        channel_name<span class="token operator">=</span>self<span class="token punctuation">.</span>name<span class="token punctuation">,</span> chat_id<span class="token operator">=</span>chat_id<span class="token punctuation">,</span> user_id<span class="token operator">=</span>user_id<span class="token punctuation">,</span></span>
<span class="line">        text<span class="token operator">=</span>text<span class="token punctuation">,</span> msg_type<span class="token operator">=</span>msg_type<span class="token punctuation">,</span> thread_ts<span class="token operator">=</span>thread_ts<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>_on_outbound</code></strong> — 出站消息回调，自动过滤目标渠道并按序发送文本和文件：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">_on_outbound</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">:</span> OutboundMessage<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> msg<span class="token punctuation">.</span>channel_name <span class="token operator">==</span> self<span class="token punctuation">.</span>name<span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">try</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">await</span> self<span class="token punctuation">.</span>send<span class="token punctuation">(</span>msg<span class="token punctuation">)</span>  <span class="token comment"># 先发文本</span></span>
<span class="line">        <span class="token keyword">except</span> Exception<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">return</span>  <span class="token comment"># 文本失败则跳过文件</span></span>
<span class="line"></span>
<span class="line">        <span class="token keyword">for</span> attachment <span class="token keyword">in</span> msg<span class="token punctuation">.</span>attachments<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">await</span> self<span class="token punctuation">.</span>send_file<span class="token punctuation">(</span>msg<span class="token punctuation">,</span> attachment<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这个设计保证了文本消息和文件附件的发送顺序，且文本发送失败时不会尝试发送孤立的文件。</p><h2 id="_20-2-messagebus-—-异步消息总线" tabindex="-1"><a class="header-anchor" href="#_20-2-messagebus-—-异步消息总线"><span>20.2 MessageBus — 异步消息总线</span></a></h2><p><code>channels/message_bus.py</code> 定义了整个渠道系统的消息模型和 Pub/Sub 中枢。</p><h3 id="消息类型" tabindex="-1"><a class="header-anchor" href="#消息类型"><span>消息类型</span></a></h3><p>系统定义了两种方向的消息：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">InboundMessageType</span><span class="token punctuation">(</span>StrEnum<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    CHAT <span class="token operator">=</span> <span class="token string">&quot;chat&quot;</span>       <span class="token comment"># 普通聊天消息</span></span>
<span class="line">    COMMAND <span class="token operator">=</span> <span class="token string">&quot;command&quot;</span>  <span class="token comment"># 斜杠命令（如 /new, /help）</span></span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@dataclass</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">InboundMessage</span><span class="token punctuation">:</span></span>
<span class="line">    channel_name<span class="token punctuation">:</span> <span class="token builtin">str</span>    <span class="token comment"># 来源渠道名</span></span>
<span class="line">    chat_id<span class="token punctuation">:</span> <span class="token builtin">str</span>         <span class="token comment"># 平台会话 ID</span></span>
<span class="line">    user_id<span class="token punctuation">:</span> <span class="token builtin">str</span>         <span class="token comment"># 平台用户 ID</span></span>
<span class="line">    text<span class="token punctuation">:</span> <span class="token builtin">str</span>            <span class="token comment"># 消息文本</span></span>
<span class="line">    msg_type<span class="token punctuation">:</span> InboundMessageType</span>
<span class="line">    thread_ts<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>   <span class="token comment"># 平台线程标识</span></span>
<span class="line">    topic_id<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>    <span class="token comment"># 映射到 DeerFlow 线程的话题 ID</span></span>
<span class="line">    files<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">dict</span><span class="token punctuation">]</span> <span class="token operator">=</span> field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">list</span><span class="token punctuation">)</span></span>
<span class="line">    metadata<span class="token punctuation">:</span> <span class="token builtin">dict</span> <span class="token operator">=</span> field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">dict</span><span class="token punctuation">)</span></span>
<span class="line">    created_at<span class="token punctuation">:</span> <span class="token builtin">float</span> <span class="token operator">=</span> field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span>time<span class="token punctuation">.</span>time<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>topic_id</code> 是连接 IM 线程和 DeerFlow 线程的关键字段。同一个 <code>topic_id</code> 内的消息会复用同一个 DeerFlow 线程，实现多轮对话。当 <code>topic_id</code> 为 <code>None</code> 时，每条消息创建独立线程。</p><p>出站消息包含文本和文件附件：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token decorator annotation punctuation">@dataclass</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">ResolvedAttachment</span><span class="token punctuation">:</span></span>
<span class="line">    virtual_path<span class="token punctuation">:</span> <span class="token builtin">str</span>    <span class="token comment"># 虚拟路径</span></span>
<span class="line">    actual_path<span class="token punctuation">:</span> Path    <span class="token comment"># 主机路径</span></span>
<span class="line">    filename<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    mime_type<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    size<span class="token punctuation">:</span> <span class="token builtin">int</span></span>
<span class="line">    is_image<span class="token punctuation">:</span> <span class="token builtin">bool</span>       <span class="token comment"># 图片可能有特殊处理</span></span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@dataclass</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">OutboundMessage</span><span class="token punctuation">:</span></span>
<span class="line">    channel_name<span class="token punctuation">:</span> <span class="token builtin">str</span>    <span class="token comment"># 目标渠道</span></span>
<span class="line">    chat_id<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    thread_id<span class="token punctuation">:</span> <span class="token builtin">str</span>       <span class="token comment"># DeerFlow 线程 ID</span></span>
<span class="line">    text<span class="token punctuation">:</span> <span class="token builtin">str</span></span>
<span class="line">    artifacts<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">=</span> field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">list</span><span class="token punctuation">)</span></span>
<span class="line">    attachments<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span>ResolvedAttachment<span class="token punctuation">]</span> <span class="token operator">=</span> field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">list</span><span class="token punctuation">)</span></span>
<span class="line">    is_final<span class="token punctuation">:</span> <span class="token builtin">bool</span> <span class="token operator">=</span> <span class="token boolean">True</span></span>
<span class="line">    thread_ts<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>is_final</code> 标记用于通知渠道这是流式响应的最后一条消息，部分渠道（如飞书）会在最终消息发送后添加&quot;完成&quot;表情回应。</p><h3 id="消息总线" tabindex="-1"><a class="header-anchor" href="#消息总线"><span>消息总线</span></a></h3><p><code>MessageBus</code> 实现了简洁的异步 Pub/Sub 模式：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">MessageBus</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>_inbound_queue<span class="token punctuation">:</span> asyncio<span class="token punctuation">.</span>Queue<span class="token punctuation">[</span>InboundMessage<span class="token punctuation">]</span> <span class="token operator">=</span> asyncio<span class="token punctuation">.</span>Queue<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_outbound_listeners<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span>OutboundCallback<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">publish_inbound</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">:</span> InboundMessage<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">await</span> self<span class="token punctuation">.</span>_inbound_queue<span class="token punctuation">.</span>put<span class="token punctuation">(</span>msg<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">get_inbound</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> InboundMessage<span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token keyword">await</span> self<span class="token punctuation">.</span>_inbound_queue<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">subscribe_outbound</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> callback<span class="token punctuation">:</span> OutboundCallback<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>_outbound_listeners<span class="token punctuation">.</span>append<span class="token punctuation">(</span>callback<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">publish_outbound</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> msg<span class="token punctuation">:</span> OutboundMessage<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">for</span> callback <span class="token keyword">in</span> self<span class="token punctuation">.</span>_outbound_listeners<span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">await</span> callback<span class="token punctuation">(</span>msg<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>入站方向使用 <code>asyncio.Queue</code>——渠道生产消息，<code>ChannelManager</code> 消费消息并调度代理处理。出站方向使用回调列表——每个渠道在启动时注册 <code>_on_outbound</code> 回调，<code>ChannelManager</code> 发布出站消息时所有渠道都会收到通知，但只有 <code>channel_name</code> 匹配的渠道才实际发送。</p><h2 id="_20-3-channelservice-—-渠道生命周期管理" tabindex="-1"><a class="header-anchor" href="#_20-3-channelservice-—-渠道生命周期管理"><span>20.3 ChannelService — 渠道生命周期管理</span></a></h2><p><code>channels/service.py</code> 中的 <code>ChannelService</code> 管理所有渠道的启停：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">_CHANNEL_REGISTRY<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> <span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token string">&quot;feishu&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;src.channels.feishu:FeishuChannel&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;slack&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;src.channels.slack:SlackChannel&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token string">&quot;telegram&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;src.channels.telegram:TelegramChannel&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">ChannelService</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> channels_config<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> Any<span class="token punctuation">]</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        self<span class="token punctuation">.</span>bus <span class="token operator">=</span> MessageBus<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>store <span class="token operator">=</span> ChannelStore<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>manager <span class="token operator">=</span> ChannelManager<span class="token punctuation">(</span></span>
<span class="line">            bus<span class="token operator">=</span>self<span class="token punctuation">.</span>bus<span class="token punctuation">,</span> store<span class="token operator">=</span>self<span class="token punctuation">.</span>store<span class="token punctuation">,</span></span>
<span class="line">            langgraph_url<span class="token operator">=</span>langgraph_url<span class="token punctuation">,</span> gateway_url<span class="token operator">=</span>gateway_url<span class="token punctuation">,</span></span>
<span class="line">            default_session<span class="token operator">=</span>default_session<span class="token punctuation">,</span> channel_sessions<span class="token operator">=</span>channel_sessions<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">await</span> self<span class="token punctuation">.</span>manager<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">for</span> name<span class="token punctuation">,</span> channel_config <span class="token keyword">in</span> self<span class="token punctuation">.</span>_config<span class="token punctuation">.</span>items<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">if</span> channel_config<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&quot;enabled&quot;</span><span class="token punctuation">,</span> <span class="token boolean">False</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">                <span class="token keyword">await</span> self<span class="token punctuation">.</span>_start_channel<span class="token punctuation">(</span>name<span class="token punctuation">,</span> channel_config<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">_start_channel</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> config<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">bool</span><span class="token punctuation">:</span></span>
<span class="line">        import_path <span class="token operator">=</span> _CHANNEL_REGISTRY<span class="token punctuation">.</span>get<span class="token punctuation">(</span>name<span class="token punctuation">)</span></span>
<span class="line">        channel_cls <span class="token operator">=</span> resolve_class<span class="token punctuation">(</span>import_path<span class="token punctuation">,</span> base_class<span class="token operator">=</span><span class="token boolean">None</span><span class="token punctuation">)</span></span>
<span class="line">        channel <span class="token operator">=</span> channel_cls<span class="token punctuation">(</span>bus<span class="token operator">=</span>self<span class="token punctuation">.</span>bus<span class="token punctuation">,</span> config<span class="token operator">=</span>config<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">await</span> channel<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_channels<span class="token punctuation">[</span>name<span class="token punctuation">]</span> <span class="token operator">=</span> channel</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>渠道的注册使用字符串导入路径，通过 <code>resolve_class</code> 反射加载——这意味着只有实际启用的渠道才会导入其依赖库（如 <code>python-telegram-bot</code>、<code>slack-sdk</code>、<code>lark-oapi</code>），未安装的库不会导致启动失败。</p><p><code>ChannelService</code> 作为全局单例，由 Gateway 的 <code>lifespan</code> 钩子在启动时创建：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start_channel_service</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> ChannelService<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">global</span> _channel_service</span>
<span class="line">    _channel_service <span class="token operator">=</span> ChannelService<span class="token punctuation">.</span>from_app_config<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">await</span> _channel_service<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> _channel_service</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_20-4-三大渠道实现" tabindex="-1"><a class="header-anchor" href="#_20-4-三大渠道实现"><span>20.4 三大渠道实现</span></a></h2><h3 id="_19-4-1-telegram" tabindex="-1"><a class="header-anchor" href="#_19-4-1-telegram"><span>19.4.1 Telegram</span></a></h3><p><code>TelegramChannel</code> 基于 <code>python-telegram-bot</code> 库，使用<strong>长轮询</strong>（Long Polling）模式，无需公网 IP：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">TelegramChannel</span><span class="token punctuation">(</span>Channel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">from</span> telegram<span class="token punctuation">.</span>ext <span class="token keyword">import</span> ApplicationBuilder<span class="token punctuation">,</span> CommandHandler<span class="token punctuation">,</span> MessageHandler<span class="token punctuation">,</span> filters</span>
<span class="line"></span>
<span class="line">        app <span class="token operator">=</span> ApplicationBuilder<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>token<span class="token punctuation">(</span>bot_token<span class="token punctuation">)</span><span class="token punctuation">.</span>build<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        app<span class="token punctuation">.</span>add_handler<span class="token punctuation">(</span>CommandHandler<span class="token punctuation">(</span><span class="token string">&quot;start&quot;</span><span class="token punctuation">,</span> self<span class="token punctuation">.</span>_cmd_start<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        app<span class="token punctuation">.</span>add_handler<span class="token punctuation">(</span>CommandHandler<span class="token punctuation">(</span><span class="token string">&quot;new&quot;</span><span class="token punctuation">,</span> self<span class="token punctuation">.</span>_cmd_generic<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        app<span class="token punctuation">.</span>add_handler<span class="token punctuation">(</span>MessageHandler<span class="token punctuation">(</span>filters<span class="token punctuation">.</span>TEXT <span class="token operator">&amp;</span> <span class="token operator">~</span>filters<span class="token punctuation">.</span>COMMAND<span class="token punctuation">,</span> self<span class="token punctuation">.</span>_on_text<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment"># 在独立线程中运行轮询</span></span>
<span class="line">        self<span class="token punctuation">.</span>_thread <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span>target<span class="token operator">=</span>self<span class="token punctuation">.</span>_run_polling<span class="token punctuation">,</span> daemon<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_thread<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Telegram 渠道在独立线程中运行事件循环，避免与主线程的 uvloop 冲突。消息处理链路为：</p><ol><li>收到用户消息后，先发送&quot;Working on it...&quot;回复</li><li>将消息封装为 <code>InboundMessage</code> 发布到 MessageBus</li><li><code>ChannelManager</code> 消费消息并调用 LangGraph Server 处理</li><li>处理结果通过 MessageBus 出站回调发送回 Telegram</li></ol><p>文件发送支持图片和文档两种模式，图片不超过 10MB 时用 <code>send_photo</code>，其余用 <code>send_document</code>（最大 50MB）。</p><p>配置示例：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">channels</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">telegram</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">enabled</span><span class="token punctuation">:</span> <span class="token boolean important">true</span></span>
<span class="line">    <span class="token key atrule">bot_token</span><span class="token punctuation">:</span> <span class="token string">&quot;123456:ABC-DEF...&quot;</span></span>
<span class="line">    <span class="token key atrule">allowed_users</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token number">12345678</span><span class="token punctuation">]</span>  <span class="token comment"># 可选，限制允许使用的用户</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_19-4-2-slack" tabindex="-1"><a class="header-anchor" href="#_19-4-2-slack"><span>19.4.2 Slack</span></a></h3><p><code>SlackChannel</code> 使用 <strong>Socket Mode</strong>（WebSocket），同样无需公网 IP：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">SlackChannel</span><span class="token punctuation">(</span>Channel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">from</span> slack_sdk <span class="token keyword">import</span> WebClient</span>
<span class="line">        <span class="token keyword">from</span> slack_sdk<span class="token punctuation">.</span>socket_mode <span class="token keyword">import</span> SocketModeClient</span>
<span class="line"></span>
<span class="line">        self<span class="token punctuation">.</span>_web_client <span class="token operator">=</span> WebClient<span class="token punctuation">(</span>token<span class="token operator">=</span>bot_token<span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_socket_client <span class="token operator">=</span> SocketModeClient<span class="token punctuation">(</span></span>
<span class="line">            app_token<span class="token operator">=</span>app_token<span class="token punctuation">,</span> web_client<span class="token operator">=</span>self<span class="token punctuation">.</span>_web_client<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_socket_client<span class="token punctuation">.</span>socket_mode_request_listeners<span class="token punctuation">.</span>append<span class="token punctuation">(</span>self<span class="token punctuation">.</span>_on_socket_event<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment"># 后台线程启动 WebSocket 连接</span></span>
<span class="line">        asyncio<span class="token punctuation">.</span>get_event_loop<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>run_in_executor<span class="token punctuation">(</span><span class="token boolean">None</span><span class="token punctuation">,</span> self<span class="token punctuation">.</span>_socket_client<span class="token punctuation">.</span>connect<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Slack 渠道有几个特色功能：</p><ul><li><strong>Markdown 转换</strong>：使用 <code>SlackMarkdownConverter</code> 将标准 Markdown 转为 Slack 的 <code>mrkdwn</code> 格式。</li><li><strong>表情反应</strong>：收到消息时添加 👀 反应表示已收到，处理完成后添加 ✅，失败时添加 ❌。</li><li><strong>线程对话</strong>：使用 Slack 的 <code>thread_ts</code> 实现话题内回复，同一话题的消息共享 DeerFlow 线程。</li></ul><p>配置需要两个 token：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">channels</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">slack</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">enabled</span><span class="token punctuation">:</span> <span class="token boolean important">true</span></span>
<span class="line">    <span class="token key atrule">bot_token</span><span class="token punctuation">:</span> <span class="token string">&quot;xoxb-...&quot;</span>   <span class="token comment"># Bot User OAuth Token</span></span>
<span class="line">    <span class="token key atrule">app_token</span><span class="token punctuation">:</span> <span class="token string">&quot;xapp-...&quot;</span>   <span class="token comment"># App-Level Token (Socket Mode)</span></span>
<span class="line">    <span class="token key atrule">allowed_users</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token string">&quot;U12345678&quot;</span><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_19-4-3-飞书" tabindex="-1"><a class="header-anchor" href="#_19-4-3-飞书"><span>19.4.3 飞书</span></a></h3><p><code>FeishuChannel</code> 使用 <code>lark-oapi</code> 的 WebSocket 长连接模式：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">FeishuChannel</span><span class="token punctuation">(</span>Channel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">start</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">import</span> lark_oapi <span class="token keyword">as</span> lark</span>
<span class="line"></span>
<span class="line">        self<span class="token punctuation">.</span>_api_client <span class="token operator">=</span> lark<span class="token punctuation">.</span>Client<span class="token punctuation">.</span>builder<span class="token punctuation">(</span><span class="token punctuation">)</span> \\</span>
<span class="line">            <span class="token punctuation">.</span>app_id<span class="token punctuation">(</span>app_id<span class="token punctuation">)</span><span class="token punctuation">.</span>app_secret<span class="token punctuation">(</span>app_secret<span class="token punctuation">)</span><span class="token punctuation">.</span>build<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">        <span class="token comment"># WebSocket 在独立线程运行</span></span>
<span class="line">        self<span class="token punctuation">.</span>_thread <span class="token operator">=</span> threading<span class="token punctuation">.</span>Thread<span class="token punctuation">(</span></span>
<span class="line">            target<span class="token operator">=</span>self<span class="token punctuation">.</span>_run_ws<span class="token punctuation">,</span> args<span class="token operator">=</span><span class="token punctuation">(</span>app_id<span class="token punctuation">,</span> app_secret<span class="token punctuation">)</span><span class="token punctuation">,</span> daemon<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span></span>
<span class="line">        self<span class="token punctuation">.</span>_thread<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">_run_ws</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> app_id<span class="token punctuation">,</span> app_secret<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        loop <span class="token operator">=</span> asyncio<span class="token punctuation">.</span>new_event_loop<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        asyncio<span class="token punctuation">.</span>set_event_loop<span class="token punctuation">(</span>loop<span class="token punctuation">)</span></span>
<span class="line">        <span class="token comment"># 修补 SDK 的模块级事件循环引用</span></span>
<span class="line">        <span class="token keyword">import</span> lark_oapi<span class="token punctuation">.</span>ws<span class="token punctuation">.</span>client <span class="token keyword">as</span> _ws_client_mod</span>
<span class="line">        _ws_client_mod<span class="token punctuation">.</span>loop <span class="token operator">=</span> loop</span>
<span class="line"></span>
<span class="line">        event_handler <span class="token operator">=</span> lark<span class="token punctuation">.</span>EventDispatcherHandler<span class="token punctuation">.</span>builder<span class="token punctuation">(</span><span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">)</span> \\</span>
<span class="line">            <span class="token punctuation">.</span>register_p2_im_message_receive_v1<span class="token punctuation">(</span>self<span class="token punctuation">.</span>_on_message<span class="token punctuation">)</span><span class="token punctuation">.</span>build<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        ws_client <span class="token operator">=</span> lark<span class="token punctuation">.</span>ws<span class="token punctuation">.</span>Client<span class="token punctuation">(</span></span>
<span class="line">            app_id<span class="token operator">=</span>app_id<span class="token punctuation">,</span> app_secret<span class="token operator">=</span>app_secret<span class="token punctuation">,</span></span>
<span class="line">            event_handler<span class="token operator">=</span>event_handler<span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span></span>
<span class="line">        ws_client<span class="token punctuation">.</span>start<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>飞书渠道的实现有一个巧妙的 workaround：<code>lark-oapi</code> SDK 在模块级缓存了事件循环引用，当主线程使用 uvloop 时会导致冲突。DeerFlow 通过在独立线程中创建新事件循环并替换 SDK 的模块级引用来解决这个问题。</p><p>飞书的消息格式使用 Interactive Card（互动卡片）渲染 Markdown 内容：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token decorator annotation punctuation">@staticmethod</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">_build_card_content</span><span class="token punctuation">(</span>text<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">str</span><span class="token punctuation">:</span></span>
<span class="line">    card <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token string">&quot;config&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;wide_screen_mode&quot;</span><span class="token punctuation">:</span> <span class="token boolean">True</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;elements&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span><span class="token string">&quot;tag&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;markdown&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;content&quot;</span><span class="token punctuation">:</span> text<span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> json<span class="token punctuation">.</span>dumps<span class="token punctuation">(</span>card<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>消息流程中的表情反应也更丰富——收到消息时添加 &quot;OK&quot; 反应，处理完成后添加 &quot;DONE&quot; 反应。</p><p>文件上传支持图片和文档两种模式，会自动根据扩展名判断文件类型（xls/ppt/pdf/doc/stream）。</p><p>配置示例：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">channels</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">feishu</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">enabled</span><span class="token punctuation">:</span> <span class="token boolean important">true</span></span>
<span class="line">    <span class="token key atrule">app_id</span><span class="token punctuation">:</span> <span class="token string">&quot;cli_xxx...&quot;</span></span>
<span class="line">    <span class="token key atrule">app_secret</span><span class="token punctuation">:</span> <span class="token string">&quot;xxx...&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_20-5-实战-配置-telegram-bot" tabindex="-1"><a class="header-anchor" href="#_20-5-实战-配置-telegram-bot"><span>20.5 实战：配置 Telegram Bot</span></a></h2><p>以下是从零开始配置 Telegram 渠道的完整步骤：</p><p><strong>第一步</strong>：在 Telegram 中找到 @BotFather，发送 <code>/newbot</code> 创建机器人，记录返回的 Bot Token。</p><p><strong>第二步</strong>：在 <code>config.yaml</code> 中添加渠道配置：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">channels</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">langgraph_url</span><span class="token punctuation">:</span> <span class="token string">&quot;http://localhost:2024&quot;</span></span>
<span class="line">  <span class="token key atrule">gateway_url</span><span class="token punctuation">:</span> <span class="token string">&quot;http://localhost:8001&quot;</span></span>
<span class="line">  <span class="token key atrule">telegram</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">enabled</span><span class="token punctuation">:</span> <span class="token boolean important">true</span></span>
<span class="line">    <span class="token key atrule">bot_token</span><span class="token punctuation">:</span> <span class="token string">&quot;123456789:AAHxxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line">    <span class="token key atrule">allowed_users</span><span class="token punctuation">:</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>  <span class="token comment"># 空列表允许所有用户</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第三步</strong>：安装依赖并启动：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh" data-title="sh"><pre><code><span class="line">uv <span class="token function">add</span> python-telegram-bot</span>
<span class="line">python <span class="token parameter variable">-m</span> uvicorn src.gateway.app:app <span class="token parameter variable">--host</span> <span class="token number">0.0</span>.0.0 <span class="token parameter variable">--port</span> <span class="token number">8001</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>启动日志应显示：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text" data-title="text"><pre><code><span class="line">INFO - Channel telegram started</span>
<span class="line">INFO - ChannelService started with channels: [&#39;telegram&#39;]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第四步</strong>：在 Telegram 中向机器人发送消息，即可开始对话。支持的命令包括 <code>/start</code>、<code>/new</code>、<code>/status</code>、<code>/models</code>、<code>/memory</code>、<code>/help</code>。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><p>DeerFlow 的 IM 渠道系统展现了优秀的架构设计：<code>Channel</code> 抽象基类定义了统一接口，<code>MessageBus</code> 通过异步 Queue 和回调列表实现了入站/出站消息的解耦，<code>ChannelService</code> 负责生命周期管理和延迟导入。三个渠道实现（Telegram、Slack、飞书）都采用了无需公网 IP 的连接方式（长轮询、Socket Mode、WebSocket），并各自处理了平台特有的消息格式、表情反应和文件上传逻辑。整个系统的扩展非常简单——只需继承 <code>Channel</code>、实现三个抽象方法、在 <code>_CHANNEL_REGISTRY</code> 中注册，即可接入新的 IM 平台。</p><hr>`,69)),s("p",null,[n[1]||(n[1]=a("来源: ",-1)),s("a",r,[n[0]||(n[0]=a("DeerFlow Book",-1)),o(e)])])])}const m=p(u,[["render",k]]),b=JSON.parse('{"path":"/docs/Agent/DeerFlow/20-im-channels.html","title":"第 20 章　IM 渠道系统","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"20.1 Channel 抽象基类","slug":"_20-1-channel-抽象基类","link":"#_20-1-channel-抽象基类","children":[]},{"level":2,"title":"20.2 MessageBus — 异步消息总线","slug":"_20-2-messagebus-—-异步消息总线","link":"#_20-2-messagebus-—-异步消息总线","children":[{"level":3,"title":"消息类型","slug":"消息类型","link":"#消息类型","children":[]},{"level":3,"title":"消息总线","slug":"消息总线","link":"#消息总线","children":[]}]},{"level":2,"title":"20.3 ChannelService — 渠道生命周期管理","slug":"_20-3-channelservice-—-渠道生命周期管理","link":"#_20-3-channelservice-—-渠道生命周期管理","children":[]},{"level":2,"title":"20.4 三大渠道实现","slug":"_20-4-三大渠道实现","link":"#_20-4-三大渠道实现","children":[{"level":3,"title":"19.4.1 Telegram","slug":"_19-4-1-telegram","link":"#_19-4-1-telegram","children":[]},{"level":3,"title":"19.4.2 Slack","slug":"_19-4-2-slack","link":"#_19-4-2-slack","children":[]},{"level":3,"title":"19.4.3 飞书","slug":"_19-4-3-飞书","link":"#_19-4-3-飞书","children":[]}]},{"level":2,"title":"20.5 实战：配置 Telegram Bot","slug":"_20-5-实战-配置-telegram-bot","link":"#_20-5-实战-配置-telegram-bot","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{},"filePathRelative":"docs/Agent/DeerFlow/20-im-channels.md"}');export{m as comp,b as data};
